import ldap

def search_ldap_by_username(ldap_server, base_dn, username):
    try:
        # Initialize the LDAP connection
        l = ldap.initialize(f"ldap://{ldap_server}")
        
        # Set options for LDAP connection (e.g., TLS)
        l.set_option(ldap.OPT_X_TLS_REQUIRE_CERT, ldap.OPT_X_TLS_NEVER)
        l.start_tls_s()
        
        # Bind to the LDAP server
        l.simple_bind_s("cn=admin,dc=example,dc=com", "password")
        
        # Search for the user by username
        search_filter = f"(uid={username})"
        attributes = ["uid", "cn", "mail"]
        result_id = l.search(base_dn, ldap.SCOPE_SUBTREE, search_filter, attributes)
        
        # Retrieve the results
        results = []
        while True:
            type_, data = l.result(result_id, 0)
            if not data:
                break
            for entry in data:
                results.append(entry[1])
        
        return results
    
    except ldap.LDAPError as e:
        print(f"LDAP error: {e}")
        return None
    
    finally:
        # Unbind from the LDAP server
        l.unbind_s()

# Example usage
